-- Runtime Actions: schema extensions enabling a new Action.Type='Runtime'
-- for agent-generated, sandbox-executed JavaScript actions, plus a universal
-- MaxExecutionTimeMS applicable to ALL action types (Custom, Generated, Runtime).
--
-- Runtime actions are JavaScript payloads that run inside the existing
-- CodeExecution sandbox (isolated-vm) and call back to the host via a
-- bidirectional bridge to access MJ capabilities (metadata, views, queries,
-- entity CRUD, other actions, agents, AI). They reuse the existing
-- CodeApprovalStatus workflow for human oversight.
--
-- Design notes:
--  * RuntimeActionConfiguration is a JSON blob (not per-column) so we can
--    evolve permission scopes, resource limits, and sandbox options without
--    further schema changes.
--  * MaxExecutionTimeMS is universal: ActionEngine enforces it via AbortSignal
--    for every action type, not just Runtime.
--  * CreatedByAgentID records which agent authored a generated action, giving
--    us an audit trail for agent-generated capabilities.

-- 1. Drop the existing Type CHECK so we can widen the allowed value set.
ALTER TABLE ${flyway:defaultSchema}.Action 
    DROP 
        CONSTRAINT CHK_Action_Type;
GO

-- 2. Add the new columns in a single ALTER TABLE. CreatedByAgentID is a
--    nullable FK to AIAgent; CodeGen will create the corresponding index.
ALTER TABLE ${flyway:defaultSchema}.Action 
    ADD
        RuntimeActionConfiguration NVARCHAR(MAX) NULL,
        MaxExecutionTimeMS INT NULL,
        CreatedByAgentID UNIQUEIDENTIFIER NULL
            CONSTRAINT FK_Action_CreatedByAgentID
            REFERENCES ${flyway:defaultSchema}.AIAgent(ID);
GO

-- 3. Recreate the Type CHECK with 'Runtime' added to the allowed values.
ALTER TABLE ${flyway:defaultSchema}.Action
    ADD CONSTRAINT CHK_Action_Type CHECK ([Type] IN ('Custom', 'Generated', 'Runtime'));
GO

-- 4. Column descriptions (consumed by CodeGen to populate EntityField metadata).

EXEC sp_addextendedproperty
    @name = N'MS_Description',
    @value = N'JSON blob holding configuration specific to Type=''Runtime'' actions: declarative permission scopes (allowedEntities, allowedActions, allowedAgents with id+name pairs), resource limits (maxMemoryMB, maxBridgeCalls), and sandbox options (additionalLibraries, debugMode). Evolvable — new keys can be introduced without schema changes. NULL for non-Runtime actions.',
    @level0type = N'SCHEMA', @level0name = N'${flyway:defaultSchema}',
    @level1type = N'TABLE',  @level1name = N'Action',
    @level2type = N'COLUMN', @level2name = N'RuntimeActionConfiguration';
GO

EXEC sp_addextendedproperty
    @name = N'MS_Description',
    @value = N'Universal maximum execution time in milliseconds for a single action invocation. Enforced by ActionEngine across ALL action types (Custom, Generated, Runtime) via AbortSignal passed through RunActionParams. NULL means use the engine default.',
    @level0type = N'SCHEMA', @level0name = N'${flyway:defaultSchema}',
    @level1type = N'TABLE',  @level1name = N'Action',
    @level2type = N'COLUMN', @level2name = N'MaxExecutionTimeMS';
GO

EXEC sp_addextendedproperty
    @name = N'MS_Description',
    @value = N'Optional reference to the AI Agent that authored this action — populated when an agent (e.g. ActionSmith) dynamically generates a Runtime action. NULL for human-authored Custom/Generated actions. Provides an audit trail linking agent-generated capabilities back to their creator.',
    @level0type = N'SCHEMA', @level0name = N'${flyway:defaultSchema}',
    @level1type = N'TABLE',  @level1name = N'Action',
    @level2type = N'COLUMN', @level2name = N'CreatedByAgentID';
GO

































